var e=[{id:`L2_1`,type:`narration`,speaker:null,text:{KOREA:`어릴 때, 숲에 들어갔다가 굶주린 곰이랑 마주친 적이 있었어.`,JPN:`小さい頃、森に入って飢えたクマと遭遇したことがあった。`,ENG:`When I was young, I went into the woods and ran into a starving bear.`,TWN:`小時候去森林裡玩，我遇到了饑餓的熊。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`narration`,speaker:null,text:{KOREA:`신기하게도 하나도 무섭지 않았어.`,JPN:`でも不思議なことに、ひとつも怖くなかった。`,ENG:`Strange as it is, I wasn't frightened at all.`,TWN:`神奇的是我一點都不害怕。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`KNIGHT_NPC_NULL_NULL`,text:{KOREA:`이, 이쪽으로 온다!!`,JPN:`む、向かってくるぞ！！`,ENG:`H-he’s coming this way!`,TWN:`往，往這邊來了！！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`KNIGHT_NPC_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`KNIGHT_NPC_NULL_NULL`,text:{KOREA:`대체 저 괴물은 뭐야! 혼자서 싸우는데 왜 상처 하나 입지 않냐고!!`,JPN:`なんだあの化け物は！　たった一人で戦っているというのに、なんで傷ひとつ付かないんだ！！`,ENG:`What is that monster?! He’s fighting alone, how is he unscathed?!`,TWN:`那個怪物究竟是什麼東西！為什麼明明孤身一人，卻還是毫髮無傷！！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:{char_id:`KNIGHT_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`KNIGHT_NPC_NULL_NULL`,text:{KOREA:`구원자님! 어디 계십니까! 구원자님!!`,JPN:`救世主様！　どこですか！　救世主様！！`,ENG:`Savior! Where are you, Savior?!`,TWN:`救贖者大人！您在哪裡！救贖者大人！！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`KNIGHT_NPC_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L12_1`,type:`narration`,speaker:null,text:{KOREA:`기억해 보면 예전부터 그랬어.`,JPN:`思い返せば、昔からそうだった。`,ENG:`I think it's always been like that.`,TWN:`仔細想想，從以前開始就一直如此。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`narration`,speaker:null,text:{KOREA:`칼을 들고 있으면 사나운 짐승도, 어떤 괴물도 무섭지 않았거든.`,JPN:`剣さえあれば、狂暴な獣も、どんな怪物も怖くなかった。`,ENG:`With a sword in my hand, no beast or monster could ever frighten me.`,TWN:`只要我手中有劍，不管是猛獸還是怪物，我便都不會害怕。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`narration`,speaker:null,text:{KOREA:`알렌은 그걸 타고난 본능 때문이라고 가르쳐 줬어.`,JPN:`アレンは、それは生まれつきの本能のせいだと教えてくれた。`,ENG:`Allen told me that I was born with certain instincts.`,TWN:`艾倫說這是與生俱來的本能。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`narration`,speaker:null,text:{KOREA:`넌 칼을 들고 있는 동안에는, 상대를 이길 수 있을지 없을지 직감적으로 알아챈다면서.`,JPN:`僕は剣を持っている間は、相手に勝てるかどうかが直感的にわかっしまうと。`,ENG:`That, while holding a sword, I instinctively know whether I can beat the enemy or not.`,TWN:`他還說我拿著劍的時候，直覺上就會知道是否能夠戰勝對手。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:null,text:{KOREA:`산개해! 비공정이 추락한다!`,JPN:`散開しろ！　飛行艇が落ちてくるぞ！`,ENG:`Disassemble! The aircraft is crashing!`,TWN:`散開！飛空艇要墜落了！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:null,text:{KOREA:`골렘도 전멸했어! 이제 끝이야……! 끝이라고!!`,JPN:`ゴーレムも全滅だ！　もう終わりだ……！　おしまいだ！！`,ENG:`All golems down! We're done for... We’re doomed!`,TWN:`泥人也全軍覆沒了！現在完了……！完了！！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`narration`,speaker:null,text:{KOREA:`내게는 필요없는 힘이었지만, 적어도 누군가를 지키는 데 쓸 수는 있었어.`,JPN:`僕には必要ない力だったけど、この力で少なくとも誰かを守ることはできた。`,ENG:`I didn't need that power, but I could at least use it to protect others.`,TWN:`雖然我不需要這樣的力量，但至少我可以用它來保護某個人。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`narration`,speaker:null,text:{KOREA:`그래서 구원자가 되어 사람들을 지키겠다고 결심했지만…….`,JPN:`だから救世主になって、みんなを守るって決めたのに……`,ENG:`Hence, I decided to be the Savior, to protect everyone...`,TWN:`所以我才下定了決心，成為保護人們的救贖者……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`ALLEN_ORDER_NULL_NULL`,text:{KOREA:`큭……. 하아…… 하……`,JPN:`くっ……はぁ……はぁ……`,ENG:`Kgh...! *Huff* *Huff*`,TWN:`咳……哈啊……哈……`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`ALLEN_ORDER_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`RAY_SCHOOL_NPC_B`,text:{KOREA:`알렌……?`,JPN:`アレン……？`,ENG:`Allen...?`,TWN:`艾倫……？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`RAY_SCHOOL_NPC_B`,face:`UNIT_SURPRISE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`ALLEN_ORDER_NULL_NULL`,text:{KOREA:`정신이 들었나……. 현자의 비약을 남겨 두길 다행이군.`,JPN:`意識が戻ったか……賢者の秘薬を残しておいたのが幸いだった。`,ENG:`You're awake... It was a wise decision to save up on the Sage's potions...`,TWN:`你醒了……幸虧智者的秘藥還有剩。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`RAY_SCHOOL_NPC_B`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`ALLEN_ORDER_NULL_NULL`,face:`UNIT_HATE`}}}}];export{e as default};